def wdc_delivery_rule(model, i):
    return model.x[i, 'boston', 'wash-dc'] + model.x[i, 'kansas-cty', 'wash-dc'] + model.x[i, 'memphis', 'wash-dc'] >= 2
model.wdc_delivery_floor = Constraint(['boston', 'chicago', 'dallas', 'kansas-cty', 'losangeles', 'memphis', 'portland', 'salt-lake'], rule=wdc_delivery_rule)

def no_chi_port_rule(model, i):
    return model.x[i, 'chicago', 'portland'] + model.x[i, 'portland', 'chicago'] <= 0
model.no_chi_port = Constraint(model.i, rule=no_chi_port_rule)

def port_handling_rule(model):
    return sum(model.x['portland', a, b] for a in model.i for b in model.i if model.darc[a, b] != 0) <= 14
model.port_handling_cap = Constraint(rule=port_handling_rule)
